--- 投骰子
function LxInstanceHandler:OnInstanceRollResp(pb)
    local instanceModule = ModuleCenter.Instance

    ---@type number 地图refId
    local mapRefId = pb.mapRefId

    local mapObj = instanceModule:GetMapObjByMapRefId(mapRefId)

    local goNum = 0
    ---@type number[] 本次随机的骰子点数
    local points = {}
    for i,v in ipairs(pb.points) do
        goNum = goNum + v
        table.insert(points,v)
    end

    ---@type number 关卡累计总点数
    local totalPoint = pb.totalPoint

    --- 可执行
    local newBreakCellMap = mapObj and mapObj.newBreakCellMap or {}

    --- 服务端：必须是没有在记录的事件里的，才可能触发，不然会重复
    local logMap = instanceModule:GetInstanceEventLog()
    ---@type LxBreakCellObj[] 首次触发的格子
    local triggerEventList = {}
    ---@type LxBreakCellObj[] 本次踩到的格子
    local breakCell = {}
    for i,v in ipairs(pb.breakCell) do
        local obj = instanceModule:NewBreakCellObj(v)
        table.insert(breakCell,obj)
        if mapObj and obj.newEvent then
            if obj.rewardFrom and #obj.rewardFrom > 0 then
                local rewardFromPointNum = 0
                for ii,vv in ipairs(obj.rewardFrom) do
                    local pointObj = mapObj:GetPointObjByCell(vv)
                    if pointObj and not pointObj.finish and not logMap[pointObj.refId] then
                        table.insert(triggerEventList,{
                            cell = vv,
                            cellReward = obj.cellReward,
                            rewardFrom = obj.rewardFrom,
                            newEvent = obj.newEvent,
                        })
                        rewardFromPointNum = rewardFromPointNum + 1
                    end
                end
                if rewardFromPointNum < 1 then
                    local cell = obj.cell
                    local pointObj = mapObj:GetPointObjByCell(cell)
                    if pointObj and not pointObj.finish and not logMap[pointObj.refId] then
                        table.insert(triggerEventList,obj)
                    end
                end
            else
                local cell = obj.cell
                local pointObj = mapObj:GetPointObjByCell(cell)
                if pointObj and not pointObj.finish and not logMap[pointObj.refId] then
                    table.insert(triggerEventList,obj)
                end
            end
        end
    end

    ---@type LxThingsInfo 总获得奖励
    local rewardInfo = ModuleCenter.Common:NewThingsInfo(pb.rewardInfo)

    local beforeFinalPoint = 0
    local gridNum = 0
    local finalPoint = 0
    local endIndex = 0
    local startTotalPoint = 0
    if mapObj then
        beforeFinalPoint = mapObj.finalPoint
        startTotalPoint = mapObj.totalPoint
        mapObj:UpdateFinalPointAndTotalPoint(totalPoint,totalPoint)
        gridNum = CtrlCenter.Instance:GetInscellTypeLenByMapRefId(mapRefId)
        finalPoint = mapObj.finalPoint
        endIndex = totalPoint % gridNum
        if endIndex == 0 then
            endIndex = gridNum
        end
    end

    FireEvent(EventNames.SEND_INSTANCE_ROLL,{
        mapRefId = mapRefId,
        goNum = goNum,
        points = points,
        startTotalPoint = startTotalPoint,
        totalPoint = totalPoint,
        breakCell = breakCell,
        rewardInfo = rewardInfo,
        beforeFinalPoint = beforeFinalPoint,
        finalPoint = finalPoint,
        endIndex = endIndex,
        gridNum = gridNum,
        triggerEventList = triggerEventList,
    })
end

--- 领取章节奖励
function LxInstanceHandler:OnInstanceMapRewardResp(pb)
    ---@type number 童话世界refId
    local worldRefId = pb.worldRefId

    local worldObj = ModuleCenter.Instance:GetWorldObj(worldRefId)
    if worldObj then
        worldObj:SetRewardReceivesList(pb.receives)
    end

    ---@type LxThingsInfo 奖励
    local rewardInfo = ModuleCenter.Common:NewThingsInfo(pb.rewardInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.InstanceMapReward, rewardInfo)
    FireEvent(EventNames.INSTANCE_MAP_REWARD)
    CtrlCenter.Instance:RefreshMainCityRP()
end

